        assert_eq!(evidence["artifact_kind"], "runtime_lane_completion_result");
        assert_eq!(evidence["completed_target"], "implementer");
        assert_eq!(
            evidence["completion_receipt_id"],
            "task-close-feature-x-dev"
        );
    });
}

